note_models.css:
/* Shared styling for the song note types. Paste into each note type's
 * "Styling" tab in Anki's note-type editor.
 *
 * Borrows the Kaiti SC font stack + hover-to-reveal ruby pinyin from the
 * word-deck note type (note_type/Chinese_anki_decks/styles.css) so the
 * song cards feel consistent with the rest of the deck collection.
 *
 * Depends on `_ruby.js` being present in Anki's collection.media/ — the
 * word decks already ship it; song templates just re-use it.
 */

.card {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  font-size: 18px;
  line-height: 1.55;
  text-align: center;
  color: #1a1a1a;
  background-color: #fafafa;
  padding: 18px 14px 24px;
  max-width: 720px;
  margin: 0 auto;
}

.night_mode .card,
.nightMode .card {
  color: #e8e8e8;
  background-color: #1c1c1e;
}

@media (prefers-color-scheme: dark) {
  body:not(.day_mode) .card {
    color: #e8e8e8;
    background-color: #1c1c1e;
  }
}

/* ---------- Tiny header ---------- */
.meta {
  font-size: 11px;
  color: #888;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  margin-bottom: 14px;
}
.night_mode .meta,
.nightMode .meta { color: #777; }

/* ---------- Hanzi + ruby block (single line) ---------- */

.hanzi-block {
  font-family: "Kaiti SC", "STKaiti", "KaiTi", "楷体", "Noto Serif CJK SC",
    "Source Han Serif SC", "Songti SC", "SimSun", "宋体", serif;
  font-size: 48px;
  line-height: 1.7;
  letter-spacing: 0.03em;
  margin: 8px 0;
  word-break: keep-all;
}

@media (max-width: 480px) {
  .hanzi-block { font-size: 38px; }
}

/* Previous-line variant on Recall cards — dimmed. */
.hanzi-block.prev { font-size: 34px; color: #888; }
.night_mode .hanzi-block.prev,
.nightMode .hanzi-block.prev { color: #aaa; }

.hanzi-block ruby {
  position: relative;
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
}

.hanzi-block ruby rt {
  font-family: "Helvetica Neue", "Segoe UI", system-ui, sans-serif;
  font-size: 0.34em;
  font-weight: 400;
  font-style: normal;
  letter-spacing: 0;
  color: #a78bfa;
  opacity: 0;
  transition: opacity 120ms ease;
  user-select: none;
}

.night_mode .hanzi-block ruby rt,
.nightMode .hanzi-block ruby rt {
  color: #c4b5fd;
}

/* Reveal: hover on desktop, .revealed for per-char tap on mobile,
 * .show-all-ruby for the global toggle. */
.hanzi-block ruby:hover rt,
.hanzi-block ruby.revealed rt,
.hanzi-block.show-all-ruby ruby rt {
  opacity: 1;
}

/* ---------- Multi-line stanza (SongBlock cards) ---------- */

.lines-block {
  font-family: "Kaiti SC", "STKaiti", "KaiTi", "楷体", "Noto Serif CJK SC",
    "Source Han Serif SC", "Songti SC", "SimSun", "宋体", serif;
  font-size: 34px;
  line-height: 1.9;
  letter-spacing: 0.03em;
  margin: 8px 0;
  word-break: keep-all;
}

@media (max-width: 480px) {
  .lines-block { font-size: 26px; }
}

.lines-block .lines-line { display: block; margin: 4px 0; }

.lines-block ruby,
.lines-block ruby rt { /* same rules as .hanzi-block */ }

.lines-block ruby {
  position: relative;
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
}

.lines-block ruby rt {
  font-family: "Helvetica Neue", "Segoe UI", system-ui, sans-serif;
  font-size: 0.34em;
  color: #a78bfa;
  opacity: 0;
  transition: opacity 120ms ease;
}

.night_mode .lines-block ruby rt,
.nightMode .lines-block ruby rt { color: #c4b5fd; }

.lines-block ruby:hover rt,
.lines-block ruby.revealed rt,
.lines-block.show-all-ruby ruby rt { opacity: 1; }

/* The blanked-line slot inside a cloze-rendered Lines block (Anki replaces
 * the cloze content with `[...]` by default). Style it as a clear gap. */
.lines-block .cloze {
  color: #b34a4a;
  font-weight: bold;
}
.night_mode .lines-block .cloze,
.nightMode .lines-block .cloze { color: #ff8080; }

/* ---------- English / Breakdown ---------- */

.english {
  font-size: 22px;
  font-style: italic;
  font-weight: 500;
  margin: 14px 0 6px;
}

.breakdown {
  font-size: 15px;
  color: #555;
  margin: 8px auto;
  line-height: 1.6;
  max-width: 600px;
}

.night_mode .breakdown,
.nightMode .breakdown { color: #a8a8a8; }

/* ---------- Recall-line prompt ---------- */

.prompt {
  font-size: 14px;
  color: #b34a4a;
  margin-top: 18px;
  letter-spacing: 0.5px;
}
.night_mode .prompt,
.nightMode .prompt { color: #ff8080; }

/* ---------- Cloze ---------- */

.cloze {
  color: #b34a4a;
  font-weight: bold;
}
.night_mode .cloze,
.nightMode .cloze { color: #ff8080; }

/* When the back-side ruby builder runs, the .cloze wrapper still surrounds
 * the rebuilt <ruby> nodes. Inherit the color so the revealed answer (and
 * its pinyin) stay accent-red even though the <rt> normally has its own
 * lavender color rule. */
.hanzi-block .cloze ruby,
.hanzi-block .cloze ruby rt,
.lines-block .cloze ruby,
.lines-block .cloze ruby rt {
  color: inherit;
}

/* ---------- Toggle button + audio replay ---------- */

.toggle-btn {
  appearance: none;
  -webkit-appearance: none;
  font-family: inherit;
  font-size: 13px;
  font-weight: 500;
  padding: 6px 14px;
  margin: 10px 4px 4px;
  border: 1px solid #d1d5db;
  border-radius: 6px;
  background: #fff;
  color: #374151;
  cursor: pointer;
  transition: background 120ms ease;
}

.toggle-btn:hover { background: #f3f4f6; }
.toggle-btn:active { background: #e5e7eb; }

.night_mode .toggle-btn,
.nightMode .toggle-btn {
  background: #2c2c2e;
  border-color: #3a3a3c;
  color: #e8e8e8;
}
.night_mode .toggle-btn:hover,
.nightMode .toggle-btn:hover { background: #3a3a3c; }

/* ---------- HR ---------- */

hr { border: none; border-top: 1px solid #e5e7eb; margin: 18px auto; max-width: 560px; }
.night_mode hr,
.nightMode hr { border-top-color: #3a3a3c; }

tmpls.qfmt:
{{#PrevHanzi}}
<div class="meta">{{SongSlug}} · what's the next line?</div>

<div class="audio">{{PrevAudio}}</div>

<div class="hanzi-block prev">{{PrevHanzi}}</div>

<div class="prompt">→ what comes next?</div>
{{/PrevHanzi}}

{{^PrevHanzi}}
<div class="meta">{{SongSlug}} · first line</div>

<div class="prompt">→ how does the song start?</div>
{{/PrevHanzi}}

